type Result<T, E = Error> =
  | { ok: true; value: T }
  | { ok: false; error: E }

function success<T>(value: T): Result<T> {
  return { ok: true, value }
}

function failure<E>(error: E): Result<never, E> {
  return { ok: false, error }
}

// Usage
