interface RetryOptions {
  maxAttempts: number
  baseDelay: number
  maxDelay: number
  retryableErrors: string[]
}

const defaultRetryOptions: RetryOptions = {
  maxAttempts: 3,
  baseDelay: 1000,
  maxDelay: 30000,
  retryableErrors: ['ECONNRESET', 'ETIMEDOUT', 'RATE_LIMITED']
}

async function withRetry<T>(
  fn: () => Promise<T>,
  options: Partial<RetryOptions> = {}
): Promise<T> {
  const opts = { ...defaultRetryOptions, ...options }
  let lastError: Error | null = null

  for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
    try {
      return await fn()
    } catch (err) {
      lastError = err as Error
      const code = (err as any).code || (err as any).name

      if (!opts.retryableErrors.includes(code)) throw err
      if (attempt === opts.maxAttempts) throw err

      const jitter = Math.random() * 0.3 + 0.85
      const delay = Math.min(
        opts.baseDelay * Math.pow(2, attempt - 1) * jitter,
        opts.maxDelay
      )
      await new Promise(resolve => setTimeout(resolve, delay))
    }
  }

  throw lastError
}

type EventMap = {
  'user.created': { id: string; email: string }
  'user.updated': { id: string; changes: Record<string, unknown> }
  'order.placed': { orderId: string; userId: string; total: number }
  'order.cancelled': { orderId: string; reason: string }
}

type EventHandler<K extends keyof EventMap> = (payload: EventMap[K]) => void

class TypedEventBus {
  private handlers = new Map<string, Set<Function>>()

  on<K extends keyof EventMap>(event: K, handler: EventHandler<K>): () => void {
    if (!this.handlers.has(event as string)) {
      this.handlers.set(event as string, new Set())
    }
    this.handlers.get(event as string)!.add(handler)
    return () => this.handlers.get(event as string)?.delete(handler)
  }

  emit<K extends keyof EventMap>(event: K, payload: EventMap[K]): void {
    this.handlers.get(event as string)?.forEach(fn => fn(payload))
  }
}

type Validator<T> = {
  validate(input: unknown): T
}

function string(): Validator<string> {
  return {
    validate(input: unknown): string {
      if (typeof input !== 'string') throw new ValidationError('Expected string')
      return input
    }
  }
}

function object<T extends Record<string, Validator<any>>>(schema: T):
  Validator<{ [K in keyof T]: ReturnType<T[K]['validate']> }> {
  return {
    validate(input: unknown) {
      if (typeof input !== 'object' || input === null) {
        throw new ValidationError('Expected object')
      }
      const result: any = {}
      for (const [key, validator] of Object.entries(schema)) {
        result[key] = (validator as Validator<any>).validate((input as any)[key])
      }
      return result
    }
  }
}

