class TokenBucket {
  private tokens: number
  private lastRefill: number

  constructor(
    private maxTokens: number,
    private refillRate: number  // tokens per second
  ) {
    this.tokens = maxTokens
    this.lastRefill = Date.now()
  }

  private refill(): void {
    const now = Date.now()
    const elapsed = (now - this.lastRefill) / 1000
    this.tokens = Math.min(
      this.maxTokens,
      this.tokens + elapsed * this.refillRate
    )
    this.lastRefill = now
  }

  tryConsume(count = 1): boolean {
    this.refill()
    if (this.tokens >= count) {
      this.tokens -= count
      return true
    }
    return false
  }

  getAvailableTokens(): number {
    this.refill()
    return this.tokens
  }
}

// Usage: 10 requests per second, burst up to 20
const limiter = new TokenBucket(20, 10)

function handleRequest(req: Request, res: Response): void {
  if (!limiter.tryConsume()) {
    res.status(429).json({ error: 'Rate limit exceeded' })
    return
  }
  // Process request
}

interface PoolResource {
  isAlive(): boolean
  close(): Promise<void>
}

class ResourcePool<T extends PoolResource> {
  private available: T[] = []
  private inUse = new Set<T>()
  private waitQueue: Array<(resource: T) => void> = []

  constructor(
    private factory: () => Promise<T>,
    private maxSize: number,
    private idleTimeoutMs: number = 30000
  ) {}

  async acquire(): Promise<T> {
    // Return an available resource if one exists
    const live = this.available.find(r => r.isAlive())
    if (live) {
      this.available = this.available.filter(r => r !== live)
      this.inUse.add(live)
      return live
    }

    // Create a new resource if under limit
    if (this.inUse.size + this.available.length < this.maxSize) {
      const resource = await this.factory()
      this.inUse.add(resource)
      return resource
    }

    // Wait for a resource to be released
    return new Promise(resolve => this.waitQueue.push(resolve))
  }

  release(resource: T): void {
    this.inUse.delete(resource)
    if (this.waitQueue.length > 0) {
      this.inUse.add(resource)
      const next = this.waitQueue.shift()!
      next(resource)
    } else {
      this.available.push(resource)
    }
  }
}

import Redis from 'ioredis'

type ChannelMap = {
  'cache:invalidate': { keys: string[] }
  'user:updated': { userId: string; fields: string[] }
  'deployment:completed': { version: string; environment: string }
}

class RedisMessageBus {
  private publisher: Redis
  private subscriber: Redis

  constructor(redisUrl: string) {
    this.publisher = new Redis(redisUrl)
    this.subscriber = new Redis(redisUrl)
  }

  async publish<K extends keyof ChannelMap>(
    channel: K,
    message: ChannelMap[K]
  ): Promise<void> {
    await this.publisher.publish(
      channel as string,
      JSON.stringify(message)
    )
  }

  async subscribe<K extends keyof ChannelMap>(
    channel: K,
    handler: (message: ChannelMap[K]) => void
  ): Promise<void> {
    await this.subscriber.subscribe(channel as string)
    this.subscriber.on('message', (ch, raw) => {
      if (ch === channel) {
        handler(JSON.parse(raw))
      }
    })
  }

  async disconnect(): Promise<void> {
    this.publisher.disconnect()
    this.subscriber.disconnect()
  }
}

enum CircuitState { Closed, Open, HalfOpen }

class CircuitBreaker {
  private state = CircuitState.Closed
  private failureCount = 0
  private lastFailureTime = 0

  constructor(
    private failureThreshold: number = 5,
    private recoveryTimeout: number = 30000,
    private halfOpenMaxCalls: number = 1
  ) {}

  async execute<T>(fn: () => Promise<T>): Promise<T> {
    if (this.state === CircuitState.Open) {
      if (Date.now() - this.lastFailureTime > this.recoveryTimeout) {
        this.state = CircuitState.HalfOpen
      } else {
        throw new Error('Circuit breaker is open')
      }
    }

    try {
      const result = await fn()
      this.onSuccess()
      return result
    } catch (err) {
      this.onFailure()
      throw err
    }
  }

  private onSuccess(): void {
    this.failureCount = 0
    this.state = CircuitState.Closed
  }

  private onFailure(): void {
    this.failureCount++
    this.lastFailureTime = Date.now()
    if (this.failureCount >= this.failureThreshold) {
      this.state = CircuitState.Open
    }
  }
}

from pydantic import BaseModel, EmailStr, field_validator
from datetime import datetime
from typing import Optional

class UserCreate(BaseModel):
    name: str
    email: EmailStr
    age: Optional[int] = None

    @field_validator('name')
    @classmethod
    def name_must_not_be_empty(cls, v: str) -> str:
        if not v.strip():
            raise ValueError('Name must not be empty')
        return v.strip()

    @field_validator('age')
    @classmethod
    def age_must_be_valid(cls, v: Optional[int]) -> Optional[int]:
        if v is not None and (v < 0 or v > 150):
            raise ValueError('Age must be between 0 and 150')
        return v

class UserResponse(UserCreate):
    id: str
    created_at: datetime

